const HOURS = 48;
const now = new Date();
const since = new Date(now.getTime() - HOURS*60*60*1000);
const IST_OFFSET_MIN = 330;
const utc = since.getTime() + (since.getTimezoneOffset()*60000);
const ist = new Date(utc + IST_OFFSET_MIN*60000);
const pad = n => String(n).padStart(2,'0');
const since_iso = `${ist.getFullYear()}-${pad(ist.getMonth()+1)}-${pad(ist.getDate())}T${pad(ist.getHours())}:${pad(ist.getMinutes())}:${pad(ist.getSeconds())}+05:30`;
return [{ json: { since_iso } }];

const JUNK = new Set(["","test","abc","asdf","xyz","demo","tbd","na","n/a","none","sample"]);
const PLACEHOLDER = new Set(["","test","abc","asdf","xyz","demo","tbd","na","n/a","null","sample","example","unknown","company","some company"]);
const TWO_PART_SUFFIXES = new Set(["co.in","com.au","co.uk","com.cn","co.jp"]);

function normalizeDomain(value) {
  if (!value) return null;
  let v = String(value).trim().toLowerCase();
  if (PLACEHOLDER.has(v)) return null;
  const schemeIdx = v.indexOf('://');
  if (schemeIdx !== -1) v = v.slice(schemeIdx + 3);
  v = v.split('/')[0].split('?')[0].split('#')[0].trim();
  if (!v || v.indexOf('.') === -1) return null;
  v = v.replace(/^www[.]/,'');
  const parts = v.split('.');
  if (parts.length < 2) return null;
  const lastTwo = parts.slice(-2).join('.');
  if (parts.length >= 3 && TWO_PART_SUFFIXES.has(lastTwo)) return parts.slice(-3).join('.');
  return parts.slice(-2).join('.');
}

function extractDomainFromText(text) {
  if (!text) return null;
  const matches = String(text).match(/[A-Za-z0-9][A-Za-z0-9.-]+[.][A-Za-z]{2,}/g) || [];
  for (const m of matches) {
    const d = normalizeDomain(m);
    if (d) return d;
  }
  return null;
}

const body = $input.first().json;
const rows = body.data || [];
const out = [];

for (const lead of rows) {
  if ((lead.Lead_Source || '') !== 'Website Lead') continue;
  if (lead.Target_Account_Name) continue;

  const company = (lead.Company || '').trim();
  let domain = normalizeDomain(lead.Website);
  let source = 'website';
  if (!domain) {
    domain = normalizeDomain(company) || extractDomainFromText(company);
    source = 'company_domain';
  }

  const result = {
    lead_id: lead.id,
    lead_name: lead.Full_Name,
    company,
    country: lead.Lead_Country,
    lead_status: lead.Lead_Status,
    domain: domain || null,
    source: domain ? source : 'unresolved',
    action: null,
    flag_reason: ''
  };

  if (!company || JUNK.has(company.toLowerCase())) {
    result.action = 'skip';
    result.flag_reason = 'Empty/placeholder Company - likely a test lead.';
  } else if (domain) {
    result.action = 'resolved_stage_b';
  } else {
    result.action = 'needs_stage_c';
    result.flag_reason = 'Bare brand name, no domain on file - needs Stage C web search (not yet wired).';
  }

  out.push({ json: result });
}

return out;

const leadItem = $('IF Needs Stage C').item.json;
const resp = $input.first().json;
let text = '';
try {
  const blocks = resp.content || [];
  for (const b of blocks) {
    if (b.type === 'text' && b.text) text += b.text;
  }
} catch (e) { text = ''; }

let parsed = null;
try {
  let t = text.trim();
  const start = t.indexOf('{');
  const end = t.lastIndexOf('}');
  if (start !== -1 && end !== -1) t = t.slice(start, end + 1);
  parsed = JSON.parse(t);
} catch (e) { parsed = null; }

const confidence = parsed && parsed.confidence ? String(parsed.confidence).toLowerCase() : null;
const domain = parsed && parsed.domain ? String(parsed.domain).toLowerCase() : null;
const isEcom = parsed ? parsed.is_ecommerce : null;

let rule, finalDomain, flag_reason;
if (!parsed || confidence !== 'high' || !domain) {
  rule = 'rule3';
  finalDomain = null;
  flag_reason = !parsed ? 'Claude response was not parseable JSON - treated as low confidence.'
    : (!domain ? 'No website found by web search.' : 'Low/medium confidence result - not trusted for auto-association.');
} else if (isEcom === true) {
  rule = 'rule1'; finalDomain = domain; flag_reason = '';
} else {
  rule = 'rule2'; finalDomain = domain; flag_reason = '';
}

return [{ json: {
  lead_id: leadItem.lead_id,
  lead_name: leadItem.lead_name,
  company: leadItem.company,
  country: leadItem.country,
  domain: finalDomain,
  rule,
  is_ecommerce: rule === 'rule1',
  flag_reason,
  source: 'stage_c_web_search'
} }];

const j = $input.first().json;
return [{ json: {
  lead_id: j.lead_id,
  lead_name: j.lead_name,
  company: j.company,
  country: j.country,
  domain: j.domain,
  rule: 'rule1',
  is_ecommerce: true,
  flag_reason: '',
  source: j.source
} }];

const src = $('Merge Rule Branches').item.json;
const resp = $input.first().json;
const row = (resp.data && resp.data[0]) || {};
let ta_id = null, created = false, error = null;
if (row.code === 'SUCCESS') {
  ta_id = row.details && row.details.id; created = true;
} else if (row.code === 'DUPLICATE_DATA') {
  ta_id = row.details && row.details.duplicate_record && row.details.duplicate_record.id;
} else if (row.code === 'MULTIPLE_OR_MULTI_ERRORS') {
  const subs = (row.details && row.details.errors) || [];
  for (const s of subs) {
    if (s.code === 'DUPLICATE_DATA') {
      ta_id = s.details && s.details.duplicate_record && s.details.duplicate_record.id;
    }
  }
  if (!ta_id) error = JSON.stringify(row);
} else {
  error = JSON.stringify(row);
}
return [{ json: Object.assign({}, src, { ta_id, created, error }) }];

const results = ($input.first().json.results) || [];
const isDryRun = true;
let rows = '';
for (const r of results) {
  const j = r.json || r;
  rows += '<tr><td>' + (j.lead_name || '') + '</td><td>' + (j.company || '') + '</td><td>' + (j.domain || j.company || '-') + '</td><td>' + (j.rule || j.action || '-') + '</td><td>' + (j.flag_reason || j.error || '') + '</td></tr>';
}
const subject = (isDryRun ? '[MAYA n8n - DRY RUN] ' : '[MAYA n8n] ') + 'Website Lead -> Target Account report - ' + (results.length) + ' processed';
const html = '<p>Daily MAYA (n8n) report.</p><table border=1 cellpadding=6 cellspacing=0><tr><th>Lead</th><th>Company</th><th>Domain / Name</th><th>Rule</th><th>Notes</th></tr>' + rows + '</table>';
return [{ json: { subject, html } }];

const src = $('Handle Create Result (Dedupe)').item.json;
const resp = $input.first().json;
const row = (resp.data && resp.data[0]) || {};
const linkOk = row.code === 'SUCCESS';
return [{ json: Object.assign({}, src, {
  link_status: linkOk ? 'linked' : 'link_failed',
  link_error: linkOk ? null : JSON.stringify(row)
}) }];
